# Use a python script to find function names at given addresses
python3 << 'EOF'
import subprocess
import re

addresses = [0x222098, 0x222234, 0x19bac0, 0x19bc14]
dbg_file = "libmonosgen-2.0.so.dbg"

# Get all function symbols sorted by address
result = subprocess.run(
    ["aarch64-linux-gnu-nm", "-C", "--defined-only", "-n", dbg_file],
    capture_output=True, text=True
)

# Parse symbols
symbols = []
for line in result.stdout.splitlines():
    parts = line.split(None, 2)
    if len(parts) >= 3:
        try:
            addr = int(parts[0], 16)
            stype = parts[1]
            name = parts[2]
            if stype.lower() in ('t', 'w'):  # text/weak symbols (functions)
                symbols.append((addr, name))
        except ValueError:
            continue

symbols.sort()

# For each target address, find the containing function
for target in addresses:
    containing = None
    for i, (addr, name) in enumerate(symbols):
        if addr > target:
            break
        containing = (addr, name)
    if containing:
        offset = target - containing[0]
        print(f"0x{target:x} => {containing[1]}+0x{offset:x} (base: 0x{containing[0]:x})")
    else:
        print(f"0x{target:x} => ???")
EOF", "description": "Map addresses to function names"}

arguments.command:
cd /tmp/sym
# Find functions containing our addresses
python3 << 'EOF'
import subprocess

addresses = [0x222098, 0x222234, 0x19bac0, 0x19bc14]

result = subprocess.run(
    ["aarch64-linux-gnu-readelf", "-sW", "mono.dbg"],
    capture_output=True, text=True
)

# Parse FUNC symbols
funcs = []
for line in result.stdout.splitlines():
    parts = line.split()
    if len(parts) >= 8 and "FUNC" in parts:
        try:
            addr = int(parts[1], 16)
            size = int(parts[2])
            name = parts[-1]
            if addr > 0:
                funcs.append((addr, size, name))
        except (ValueError, IndexError):
            continue

funcs.sort()

for target in addresses:
    found = None
    for addr, size, name in funcs:
        if addr <= target < addr + size:
            found = (addr, size, name)
            break
        if addr > target:
            break
    if found:
        offset = target - found[0]
        print(f"0x{target:x} => {found[2]}+0x{offset:x}")
    else:
        # fallback: find closest function before
        closest = None
        for addr, size, name in funcs:
            if addr <= target:
                closest = (addr, size, name)
            else:
                break
        if closest:
            offset = target - closest[0]
            print(f"0x{target:x} => {closest[2]}+0x{offset:x} (approx, size={closest[1]})")
        else:
            print(f"0x{target:x} => ???")
EOF

